ValidationRule.errorConditionFormula:
AND(
    NOT(
        OR(
            RecordType.DeveloperName = "SalesNote",
            RecordType.DeveloperName = "ProductOrder",
            ISPICKVAL(Status, "Concluído")
        )
    ),
    OR(
        (ISCHANGED(EndDate) && NOT(ISNULL(PRIORVALUE(EndDate)))),
        ISCHANGED(EffectiveDate)
    )
)
